import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';

export interface Note {
  id?: string;
  titulo: string;
  contenido: string;
  tipo?: string;
  etiquetas?: string;
  checklist?: any;
  recordatorio?: Date;
  archivada?: boolean;
}

@Component({
  selector: 'app-note-card',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './note-card.component.html',
  styleUrls: ['./note-card.component.scss'],
})
export class NoteCardComponent {
  @Input() note!: Note;
  @Output() noteClick = new EventEmitter<string>();
  @Output() archive = new EventEmitter<string>();
  @Output() delete = new EventEmitter<string>();

  onNoteClick(): void {
    this.noteClick.emit(this.note.id);
  }

  onArchive(event: Event): void {
    event.stopPropagation();
    this.archive.emit(this.note.id);
  }

  onDelete(event: Event): void {
    event.stopPropagation();
    this.delete.emit(this.note.id);
  }
}
<div class="note-card" (click)="onNoteClick()" [class.archived]="note.archivada">
  <h3>{{ note.titulo }}</h3>
  <p class="note-content">{{ note.contenido | slice:0:100 }}{{ note.contenido.length > 100 ? '...' : '' }}</p>

  <div class="note-actions">
    <button class="archive-btn" (click)="onArchive($event)" [title]="note.archivada ? 'Desarchivar' : 'Archivar'">
      {{ note.archivada ? '📤' : '📦' }}
    </button>
    <button class="delete-btn" (click)="onDelete($event)" title="Eliminar">
      🗑️
    </button>
  </div>

  <div class="note-meta" *ngIf="note.etiquetas || note.recordatorio">
    <span *ngIf="note.etiquetas">🏷️ {{ note.etiquetas }}</span>
    <span *ngIf="note.recordatorio">⏰ {{ note.recordatorio | date:'short' }}</span>
  </div>
</div>
